// Server-only module: holds the shared counter value and the registry of
// subscribers (SSE response writers) used by the streaming endpoint. This file
// is only imported by server endpoints, so its code is never included in any
// client bundle that the Qwik optimizer produces.
//
// In Qwik City's dev server (vite --mode ssr), the Node.js process is
// persistent across requests, so this module's module-level state is naturally
// shared by every incoming request that touches it.

/**
 * The shape of the data we push over SSE. JSON-serialized into the
 * `data:` payload of each Server-Sent Event frame.
 */
export interface CounterPayload {
  count: number;
}

/**
 * A minimal interface that abstracts the writer we need to push events to.
 * `QwikCity`'s `RequestEvent.getWritableStream()` returns a
 * `WritableStreamDefaultWriter<Uint8Array>`, but we keep the surface tiny so
 * the module stays trivial to test and has no Qwik-city coupling outside the
 * endpoints that import it.
 */
export interface CounterWriter {
  write(chunk: Uint8Array): Promise<void>;
  close?(): Promise<void>;
}

/**
 * The single, process-wide counter. It is intentionally a module-local `let`
 * (no `globalThis` indirection) because Qwik City's dev SSR server keeps the
 * Node.js process alive across requests, so all requests observe the same
 * module instance and therefore the same value.
 */
let count = 0;

/**
 * Registry of currently connected SSE subscribers. We key by the writer
 * itself (identity), since the writer uniquely identifies a connection.
 */
const subscribers = new Set<CounterWriter>();

/**
 * Encode one SSE frame for the given payload. The format is the spec'd
 * text/event-stream data frame:
 *
 *   data: <single-line JSON>\n
 *   \n
 *
 * The payload is forced onto a single line by JSON.stringify (which never
 * emits raw newlines), then a blank line terminates the frame as required.
 */
export function encodeSseFrame(payload: CounterPayload): Uint8Array {
  const json = JSON.stringify(payload);
  const frame = `data: ${json}\n\n`;
  return new TextEncoder().encode(frame);
}

/**
 * Current shared counter value. Pure read.
 */
export function getCount(): number {
  return count;
}

/**
 * Register an SSE writer as a subscriber. Returns an `unsubscribe` function
 * that, when called, idempotently removes the writer from the registry.
 * Callers should invoke `unsubscribe` when the underlying connection ends
 * (e.g. on `requestEvent.signal` abort).
 */
export function addSubscriber(writer: CounterWriter): () => void {
  subscribers.add(writer);
  return () => {
    subscribers.delete(writer);
  };
}

/**
 * Push a payload to every registered subscriber. Errors from individual
 * writers (closed/aborted connections, network errors, etc.) are swallowed
 * and the offending writer is dropped from the registry so a single broken
 * client cannot stall the broadcast loop.
 */
export async function broadcast(payload: CounterPayload): Promise<void> {
  const frame = encodeSseFrame(payload);
  const dead: CounterWriter[] = [];
  for (const writer of subscribers) {
    try {
      await writer.write(frame);
    } catch {
      dead.push(writer);
    }
  }
  for (const writer of dead) {
    subscribers.delete(writer);
  }
}

/**
 * Apply a signed delta to the shared counter and fan the new value out to
 * every connected subscriber. The update is atomic from the point of view
 * of the broadcaster (no awaits between read and write), so concurrent
 * mutations can't interleave a stale value into the broadcast.
 *
 * Returns the new counter value, which the POST endpoint mirrors back to the
 * caller in its JSON response.
 */
export async function updateCounter(delta: number): Promise<number> {
  count = count + delta;
  await broadcast({ count });
  return count;
}

// Counter REST endpoints.
//
//   GET  /api/counter     -> { count: number }   (current value)
//   POST /api/counter     -> { count: number }   (apply signed delta, broadcast)
//
// Both handlers delegate the shared state and broadcast logic to the
// server-only module in ~/lib/counter, so this file contains no mutable
// state of its own and is safe to import elsewhere.
import type { RequestHandler } from "@builder.io/qwik-city";
import { getCount, updateCounter } from "~/lib/counter";

/**
 * Return the current counter value as JSON.
 */
export const onGet: RequestHandler = async (requestEvent) => {
  const count = getCount();
  requestEvent.json(200, { count });
};

/**
 * Apply a signed delta to the shared counter and broadcast the resulting
 * value to every connected SSE subscriber.
 *
 * Request body is JSON of the shape `{ "delta": <integer> }`. The delta may
 * be negative to decrement. After the mutation the new value is mirrored
 * back in the response body so the originating client does not have to wait
 * for its own SSE frame to learn the result.
 */
export const onPost: RequestHandler = async (requestEvent) => {
  // parseBody returns a parsed JSON value for application/json requests,
  // falling back to URL-encoded / form data, or {} when there is no body.
  const body = (await requestEvent.parseBody()) as { delta?: unknown };
  const raw = body?.delta;

  // Reject anything that isn't a real number. We intentionally refuse to
  // coerce strings/booleans so the contract is tight.
  if (typeof raw !== "number" || !Number.isFinite(raw)) {
    requestEvent.json(400, { error: "delta must be a finite number" });
    return;
  }

  // Coerce to integer. The shared state is an integer counter, so a delta
  // like 1.7 would silently drift otherwise.
  const delta = Math.trunc(raw);

  const count = await updateCounter(delta);
  requestEvent.json(200, { count });
};

// SSE streaming endpoint: GET /api/counter/stream
//
// On connect we register the response writer with the shared counter
// registry, immediately push the current value as one SSE frame, then keep
// the connection open. Every time another client mutates the counter, the
// POST endpoint broadcasts the new value to every registered writer,
// including ours, so the browser sees each change live.
//
// On disconnect (client navigation away, network drop, explicit close) we
// remove the writer from the registry so a future broadcast doesn't try to
// write to a dead stream.
import type { RequestHandler } from "@builder.io/qwik-city";
import {
  addSubscriber,
  encodeSseFrame,
  getCount,
  type CounterWriter,
} from "~/lib/counter";

export const onGet: RequestHandler = async (requestEvent) => {
  // Spec'd SSE headers. We set the status explicitly to 200 (the default
  // for onGet) because intermediaries sometimes gate on it.
  requestEvent.headers.set("Content-Type", "text/event-stream");
  requestEvent.headers.set("Cache-Control", "no-cache, no-transform");
  requestEvent.headers.set("Connection", "keep-alive");
  // Disable Nginx-style buffering when running behind a reverse proxy.
  requestEvent.headers.set("X-Accel-Buffering", "no");
  requestEvent.status(200);

  // Acquire the writable half of the response. Qwik City hands us a web
  // standard WritableStream; we then get the default writer from it. We
  // close the response ourselves in the abort handler below.
  const writable = requestEvent.getWritableStream();
  const writer = writable.getWriter();

  // Adapter from the WritableStreamDefaultWriter shape (Uint8Array, throws
  // DOMException on closed/aborted streams) to the tiny CounterWriter
  // interface used by ~/lib/counter.
  const counterWriter: CounterWriter = {
    async write(chunk: Uint8Array): Promise<void> {
      await writer.write(chunk);
    },
    async close(): Promise<void> {
      await writer.close();
    },
  };

  // Register ourselves as a subscriber. The returned function is idempotent,
  // so it's safe to call it more than once from the abort listener and from
  // the finally-style teardown.
  const unsubscribe = addSubscriber(counterWriter);

  // Send the current value immediately so a freshly connected client doesn't
  // have to wait for the next mutation to see something on screen. We do
  // this after registration so a broadcast that races us still reaches us.
  try {
    await writer.write(encodeSseFrame({ count: getCount() }));
  } catch {
    // The client may have already aborted between us getting the writer
    // and writing the initial frame; in that case just bail and let the
    // abort handler below clean up the registry.
    unsubscribe();
    return;
  }

  // When the client disconnects (tab closed, navigation, network drop,
  // explicit close), Qwik City surfaces that via requestEvent.signal. We
  // drop ourselves from the registry and release the writer; broadcasting
  // throws on a released writer, so cleaning up here is what keeps the
  // registry tight.
  const cleanup = () => {
    unsubscribe();
    try {
      writer.releaseLock();
    } catch {
      // Already released; nothing to do.
    }
  };
  requestEvent.signal.addEventListener("abort", cleanup);

  // Tell Qwik City not to end the request when the handler returns. This
  // keeps the underlying socket open so writers we push to reach the
  // browser. We register the abort listener above as the sole termination
  // signal for this long-lived response.
  requestEvent.signal.addEventListener(
    "abort",
    () => {
      // Listener registered so Qwik keeps the request alive for the
      // subscriber's lifetime; the actual work happens in `cleanup`.
    },
    { once: true },
  );
};

// Home page: subscribes to the SSE counter stream, renders the latest value
// inside an element with id="counter-value", and lets the user mutate the
// counter locally. The whole subscription is wired up in a visible task so
// it only runs in the browser, and the cleanup callback closes the
// EventSource when the component is torn down.
import {
  $,
  component$,
  useSignal,
  useVisibleTask$,
} from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";

export default component$(() => {
  // Reactive holder for the latest counter value we have observed over SSE.
  const count = useSignal(0);
  // User-supplied delta for the +/- buttons.
  const delta = useSignal(1);

  // Browser-only subscription. useVisibleTask$ runs once the component is
  // mounted in the DOM, so EventSource (a browser-only API) is safe here.
  // The cleanup callback is invoked when the component is destroyed.
  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(({ cleanup }) => {
    const url = "/api/counter/stream";
    const source = new EventSource(url);

    source.onopen = () => {
      // Connection is established; nothing else to do. The server pushes an
      // initial frame as soon as we register, so the first `count` event
      // below will deliver the current value.
    };

    source.onerror = () => {
      // EventSource auto-reconnects on transient errors. We don't need to
      // do anything explicit; if the connection is permanently down (e.g.
      // server stopped) the EventSource will keep retrying in the
      // background and the user will see the last successful value until
      // a new one arrives.
    };

    source.onmessage = (event: MessageEvent<string>) => {
      // The server emits frames as `data: {"count": <int>}\n\n`. Parse the
      // payload and update our signal so the DOM re-renders.
      try {
        const payload = JSON.parse(event.data) as { count: number };
        if (typeof payload.count === "number") {
          count.value = payload.count;
        }
      } catch {
        // Ignore malformed frames; the next broadcast will overwrite.
      }
    };

    // When the component is destroyed (route change, full-page reload, etc.)
    // we tear down the EventSource so the browser doesn't keep the
    // connection alive in the background.
    cleanup(() => {
      source.close();
    });
  });

  // Click handlers that POST a signed delta to /api/counter. Optimistically
  // apply the delta locally so the UI feels snappy; the SSE stream will
  // confirm the new value (and broadcast it to every other client).
  const adjust = $(async (sign: 1 | -1) => {
    const effectiveDelta = sign * Math.trunc(Number(delta.value) || 0);
    if (effectiveDelta === 0) return;
    try {
      await fetch("/api/counter", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ delta: effectiveDelta }),
      });
    } catch {
      // Swallow network errors here; the SSE stream is the source of truth
      // and will redisplay whatever value the server eventually settles on.
    }
  });

  return (
    <main style={{ fontFamily: "system-ui, sans-serif", padding: "2rem" }}>
      <h1>Live Shared Counter</h1>
      <p style={{ fontSize: "1rem", color: "#555" }}>
        This counter is shared across every connected browser. Open this page
        in multiple tabs or windows and try clicking the buttons &mdash; all
        windows update together.
      </p>

      <div
        style={{
          margin: "1.5rem 0",
          padding: "1.5rem",
          border: "1px solid #ddd",
          borderRadius: "8px",
          display: "inline-block",
          minWidth: "320px",
          background: "#fafafa",
        }}
      >
        <div style={{ fontSize: "0.85rem", color: "#777" }}>Current value</div>
        <div
          id="counter-value"
          data-testid="counter-value"
          style={{
            fontSize: "4rem",
            fontWeight: 700,
            fontVariantNumeric: "tabular-nums",
            lineHeight: 1.1,
          }}
        >
          {count.value}
        </div>

        <div style={{ marginTop: "1rem", display: "flex", gap: "0.5rem" }}>
          <input
            type="number"
            value={delta.value}
            onInput$={(_, el) => {
              delta.value = Number(el.value);
            }}
            style={{ width: "6rem", padding: "0.4rem" }}
          />
          <button onClick$={() => adjust(-1)} style={{ padding: "0.4rem 1rem" }}>
            -
          </button>
          <button onClick$={() => adjust(1)} style={{ padding: "0.4rem 1rem" }}>
            +
          </button>
        </div>
      </div>

      <p style={{ fontSize: "0.85rem", color: "#888" }}>
        Updates flow over a Server-Sent Events stream from{" "}
        <code>GET /api/counter/stream</code>. Mutations are sent to{" "}
        <code>POST /api/counter</code> with a JSON body of{" "}
        <code>{`{ "delta": <int> }`}</code>.
      </p>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Live Shared Counter (SSE)",
  meta: [
    {
      name: "description",
      content:
        "A Qwik City app showing a shared counter pushed to the browser over Server-Sent Events.",
    },
  ],
};

